using Microsoft.Data.SqlClient;
using System.Data;
using SistemaControlEmpleados.Models;
namespace SistemaControlEmpleados.Data;
public class AppRepository {
 private readonly Db _db; public AppRepository(Db db)=>_db=db;
 private static T Get<T>(SqlDataReader r,string col){ var v=r[col]; return v==DBNull.Value?default!: (T)v; }

// este objeto me deja llamar a mis objetos de base de datos
 private async Task<List<T>> Query<T>(string sp, Func<SqlDataReader,T> map, params SqlParameter[] ps){ var list=new List<T>(); await using var cn=_db.Create(); await using var cmd=new SqlCommand(sp,cn){CommandType=CommandType.StoredProcedure}; cmd.Parameters.AddRange(ps); await cn.OpenAsync(); await using var rd=await cmd.ExecuteReaderAsync(); while(await rd.ReadAsync()) list.Add(map(rd)); return list;}
 private async Task<int> Exec(string sp, params SqlParameter[] ps){ await using var cn=_db.Create(); await using var cmd=new SqlCommand(sp,cn){CommandType=CommandType.StoredProcedure}; cmd.Parameters.AddRange(ps); await cn.OpenAsync(); return await cmd.ExecuteNonQueryAsync(); }
 public Task<List<Departamento>> Departamentos()=>Query("sp_Departamento_Listar", r=>new Departamento{Id=Get<int>(r,"Id"),Codigo=Get<string>(r,"Codigo"),Nombre=Get<string>(r,"Nombre"),Descripcion=Get<string?>(r,"Descripcion")});
 public async Task<Departamento?> Departamento(int id)=>(await Query("sp_Departamento_Obtener", r=>new Departamento{Id=Get<int>(r,"Id"),Codigo=Get<string>(r,"Codigo"),Nombre=Get<string>(r,"Nombre"),Descripcion=Get<string?>(r,"Descripcion")}, new SqlParameter("@Id",id))).FirstOrDefault();
 public Task CrearDepartamento(Departamento x)=>Exec("sp_Departamento_Crear",new SqlParameter("@Codigo",x.Codigo),new SqlParameter("@Nombre",x.Nombre),new SqlParameter("@Descripcion",(object?)x.Descripcion??DBNull.Value));
 public Task ActualizarDepartamento(Departamento x)=>Exec("sp_Departamento_Actualizar",new SqlParameter("@Id",x.Id),new SqlParameter("@Codigo",x.Codigo),new SqlParameter("@Nombre",x.Nombre),new SqlParameter("@Descripcion",(object?)x.Descripcion??DBNull.Value));
 public Task EliminarDepartamento(int id)=>Exec("sp_Departamento_Eliminar",new SqlParameter("@Id",id));
 public Task<List<Empleado>> Empleados()=>Query("sp_Empleado_Listar", r=>new Empleado{Id=Get<int>(r,"Id"),Codigo=Get<string>(r,"Codigo"),Nombres=Get<string>(r,"Nombres"),Apellidos=Get<string>(r,"Apellidos"),FechaNacimiento=Get<DateTime?>(r,"FechaNacimiento"),DepartamentoId=Get<int>(r,"DepartamentoId"),Departamento=Get<string>(r,"Departamento")});
 public async Task<Empleado?> Empleado(int id)=>(await Query("sp_Empleado_Obtener", r=>new Empleado{Id=Get<int>(r,"Id"),Codigo=Get<string>(r,"Codigo"),Nombres=Get<string>(r,"Nombres"),Apellidos=Get<string>(r,"Apellidos"),FechaNacimiento=Get<DateTime?>(r,"FechaNacimiento"),DepartamentoId=Get<int>(r,"DepartamentoId"),Departamento=Get<string>(r,"Departamento")}, new SqlParameter("@Id",id))).FirstOrDefault();
 public Task CrearEmpleado(Empleado x)=>Exec("sp_Empleado_Crear",new SqlParameter("@Nombres",x.Nombres),new SqlParameter("@Apellidos",x.Apellidos),new SqlParameter("@FechaNacimiento",(object?)x.FechaNacimiento??DBNull.Value),new SqlParameter("@DepartamentoId",x.DepartamentoId));
 public Task ActualizarEmpleado(Empleado x)=>Exec("sp_Empleado_Actualizar",new SqlParameter("@Id",x.Id),new SqlParameter("@Nombres",x.Nombres),new SqlParameter("@Apellidos",x.Apellidos),new SqlParameter("@FechaNacimiento",(object?)x.FechaNacimiento??DBNull.Value),new SqlParameter("@DepartamentoId",x.DepartamentoId));
 public Task EliminarEmpleado(int id)=>Exec("sp_Empleado_Eliminar",new SqlParameter("@Id",id));
 public Task<List<Presupuesto>> Presupuestos()=>Query("sp_Presupuesto_Listar", r=>new Presupuesto{Id=Get<int>(r,"Id"),DepartamentoId=Get<int>(r,"DepartamentoId"),Departamento=Get<string>(r,"Departamento"),Monto=Get<decimal>(r,"Monto"),FechaAsignacion=Get<DateTime>(r,"FechaAsignacion"),Observacion=Get<string?>(r,"Observacion")});
 public async Task<Presupuesto?> Presupuesto(int id)=>(await Query("sp_Presupuesto_Obtener", r=>new Presupuesto{Id=Get<int>(r,"Id"),DepartamentoId=Get<int>(r,"DepartamentoId"),Departamento=Get<string>(r,"Departamento"),Monto=Get<decimal>(r,"Monto"),FechaAsignacion=Get<DateTime>(r,"FechaAsignacion"),Observacion=Get<string?>(r,"Observacion")}, new SqlParameter("@Id",id))).FirstOrDefault();
 public Task CrearPresupuesto(Presupuesto x)=>Exec("sp_Presupuesto_Crear",new SqlParameter("@DepartamentoId",x.DepartamentoId),new SqlParameter("@Monto",x.Monto),new SqlParameter("@FechaAsignacion",x.FechaAsignacion),new SqlParameter("@Observacion",(object?)x.Observacion??DBNull.Value));
 public Task ActualizarPresupuesto(Presupuesto x)=>Exec("sp_Presupuesto_Actualizar",new SqlParameter("@Id",x.Id),new SqlParameter("@DepartamentoId",x.DepartamentoId),new SqlParameter("@Monto",x.Monto),new SqlParameter("@FechaAsignacion",x.FechaAsignacion),new SqlParameter("@Observacion",(object?)x.Observacion??DBNull.Value));
 public Task EliminarPresupuesto(int id)=>Exec("sp_Presupuesto_Eliminar",new SqlParameter("@Id",id));
 public Task<List<Gasto>> Gastos()=>Query("sp_Gasto_Listar", r=>new Gasto{Id=Get<int>(r,"Id"),EmpleadoId=Get<int>(r,"EmpleadoId"),Empleado=Get<string>(r,"Empleado"),Departamento=Get<string>(r,"Departamento"),Monto=Get<decimal>(r,"Monto"),FechaGasto=Get<DateTime>(r,"FechaGasto"),Descripcion=Get<string>(r,"Descripcion")});
 public async Task<Gasto?> Gasto(int id)=>(await Query("sp_Gasto_Obtener", r=>new Gasto{Id=Get<int>(r,"Id"),EmpleadoId=Get<int>(r,"EmpleadoId"),Empleado=Get<string>(r,"Empleado"),Departamento=Get<string>(r,"Departamento"),Monto=Get<decimal>(r,"Monto"),FechaGasto=Get<DateTime>(r,"FechaGasto"),Descripcion=Get<string>(r,"Descripcion")}, new SqlParameter("@Id",id))).FirstOrDefault();
 public Task CrearGasto(Gasto x)=>Exec("sp_Gasto_Crear",new SqlParameter("@EmpleadoId",x.EmpleadoId),new SqlParameter("@Monto",x.Monto),new SqlParameter("@FechaGasto",x.FechaGasto),new SqlParameter("@Descripcion",x.Descripcion));
 public Task ActualizarGasto(Gasto x)=>Exec("sp_Gasto_Actualizar",new SqlParameter("@Id",x.Id),new SqlParameter("@EmpleadoId",x.EmpleadoId),new SqlParameter("@Monto",x.Monto),new SqlParameter("@FechaGasto",x.FechaGasto),new SqlParameter("@Descripcion",x.Descripcion));
 public Task EliminarGasto(int id)=>Exec("sp_Gasto_Eliminar",new SqlParameter("@Id",id));
 public Task<List<ReportePresupuesto>> Reporte()=>Query("sp_Reporte_PresupuestoDepartamentos", r=>new ReportePresupuesto{DepartamentoId=Get<int>(r,"DepartamentoId"),Codigo=Get<string>(r,"Codigo"),Departamento=Get<string>(r,"Departamento"),PresupuestoAsignado=Get<decimal>(r,"PresupuestoAsignado"),PresupuestoUtilizado=Get<decimal>(r,"PresupuestoUtilizado"),Disponible=Get<decimal>(r,"Disponible"),PorcentajeEjecucion=Get<decimal>(r,"PorcentajeEjecucion")});
}
